  router.get("/customers", requireAuth, async (req: Request, res: Response) => {
    try {
      const business = await getBusinessByOwner(req.session.userId!);
      if (!business) return res.status(404).json({ message: "Business not found" });
      const { search, status, page, limit } = req.query as any;

      if (page !== undefined || limit !== undefined) {
        const pageNum = Math.max(1, parseInt(page || "1", 10));
        const limitNum = Math.min(100, Math.max(1, parseInt(limit || "50", 10)));
        const offset = (pageNum - 1) * limitNum;

        const searchConditions = search
          ? or(
              ilike(customers.firstName, `%${search}%`),
              ilike(customers.lastName, `%${search}%`),
              ilike(customers.email, `%${search}%`)
            )
          : undefined;

        const whereClause = searchConditions
          ? and(eq(customers.businessId, business.id), isNull(customers.deletedAt), searchConditions)
          : and(eq(customers.businessId, business.id), isNull(customers.deletedAt));

        const [countResult, list] = await Promise.all([
          db.select({ count: sql<number>`count(*)::int` }).from(customers).where(whereClause),
          db.select().from(customers).where(whereClause).orderBy(desc(customers.updatedAt)).limit(limitNum).offset(offset),
        ]);

        const total = countResult[0]?.count ?? 0;
        const totalPages = Math.ceil(total / limitNum);
        return res.json({ customers: list, total, page: pageNum, totalPages, hasMore: pageNum < totalPages });
      }

      const list = await getCustomersByBusiness(business.id, { search, status });

      // Attach lifetime value (sum of accepted quotes) to each customer
      const ltvRows = await db
        .select({
          customerId: quotes.customerId,
          lifetimeValue: sql<number>`COALESCE(SUM(CASE WHEN ${quotes.status} = 'accepted' THEN ${quotes.total} ELSE 0 END), 0)`,
          quoteCount: sql<number>`COUNT(*)::int`,
        })
        .from(quotes)
        .where(and(eq(quotes.businessId, business.id), isNull(quotes.deletedAt)))
        .groupBy(quotes.customerId);

      const ltvMap = new Map(ltvRows.map((r) => [r.customerId, { lifetimeValue: Number(r.lifetimeValue), quoteCount: r.quoteCount }]));

      const enriched = list.map((c: any) => ({
        ...c,
        lifetimeValue: ltvMap.get(c.id)?.lifetimeValue ?? 0,
        quoteCount: ltvMap.get(c.id)?.quoteCount ?? 0,
      }));

      return res.json(enriched);
    } catch (error: any) {
      console.error("Get customers error:", error);
      return res.status(500).json({ message: "Failed to get customers" });
    }
  });

